--
-- Table structure for table `OPTIONS`
--

DROP TABLE IF EXISTS `OPTIONS`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `OPTIONS` (
  `OPTIONS_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '옵션 ID',
  `QUESTION_ID` bigint DEFAULT NULL COMMENT '질문 ID',
  `OPTIONS_ORDERS` int DEFAULT NULL COMMENT '옵션 순서',
  `OPTIONS_TITLE` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '옵션 제목',
  `OPTIONS_DESCRIPTION` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '옵션 설명',
  `OPTIONS_TYPE` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '옵션 타입',
  `OPTIONS_THUMBNAIL` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '옵션 썸네일',
  `OPTIONS_MIN_LENGTH` int DEFAULT NULL COMMENT '옵션 최소 길이',
  `OPTIONS_MAX_LENGTH` int DEFAULT NULL COMMENT '옵션 최대 길이',
  `OPTIONS_JSON` text COLLATE utf8mb4_unicode_ci COMMENT '옵션 제이슨',
  `OPTIONS_MIN_LENGTH_IS_ACTIVE` tinyint DEFAULT NULL COMMENT '옵션 최소 길이 여부 활성',
  `OPTIONS_IS_ACTIVE` tinyint DEFAULT NULL COMMENT '옵션 여부 활성',
  `REGIST_DATE` datetime DEFAULT (now()) COMMENT '생성 일시',
  `MODIFY_DATE` datetime DEFAULT (now()) COMMENT '수정 일시',
  PRIMARY KEY (`OPTIONS_ID`),
  KEY `FK_OPTIONS_QUESTION_ID_QUESTION_QUESTION_ID` (`QUESTION_ID`),
  CONSTRAINT `FK_OPTIONS_QUESTION_ID_QUESTION_QUESTION_ID` FOREIGN KEY (`QUESTION_ID`) REFERENCES `QUESTION` (`QUESTION_ID`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1949 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

