/*!40000 ALTER TABLE `OPTIONS` DISABLE KEYS */;
INSERT INTO `OPTIONS` VALUES (1212,449,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1213,450,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1214,450,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:27:31','2026-01-14 11:40:28'),(1215,450,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1216,450,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1217,450,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1218,450,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1219,450,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 18:27:31','2026-01-14 13:59:14'),(1220,450,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1221,450,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1222,450,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:27:31','2026-01-14 11:41:10'),(1223,451,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:27:31','2026-01-13 17:03:28'),(1224,451,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:27:31','2026-01-13 17:03:34'),(1225,451,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 작성해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인 주소가 있다면 작성해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 18:27:31','2026-01-14 15:33:28'),(1226,451,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1227,452,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등\r\n','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 18:27:31','2026-02-13 14:55:42'),(1228,452,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 18:27:31','2026-01-14 14:00:58'),(1229,453,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해 주세요.\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:27:31','2026-01-14 15:40:18'),(1230,453,3,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:27:31','2026-01-14 15:29:10'),(1231,453,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/9e6be028-afb9-4310-9bda-07eed432f4e1.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 18:27:31','2026-01-13 16:36:58'),(1232,453,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/a4c9cf32-841b-4d45-866e-fffac32d48c0.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:27:31','2026-01-13 16:37:06'),(1233,453,2,'로고 제작 옵션을 선택해 주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 18:27:31','2026-01-14 15:43:28'),(1234,454,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1235,454,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"multiple\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}]}',0,0,'2026-01-09 18:27:31','2026-01-14 13:59:34'),(1236,455,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1237,456,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1238,457,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 18:27:31','2026-01-14 14:10:10'),(1239,457,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1242,458,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 18:27:31','2026-01-09 18:27:31'),(1274,469,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1275,470,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1276,470,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:49:46','2026-01-14 11:41:24'),(1277,470,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1278,470,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1279,470,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1280,470,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1281,470,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 18:49:46','2026-01-14 14:18:43'),(1282,470,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1283,470,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1284,470,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:49:46','2026-01-14 11:41:30'),(1285,471,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:49:46','2026-01-13 17:03:54'),(1286,471,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:49:46','2026-01-13 17:03:57'),(1287,471,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 18:49:46','2026-01-14 15:34:08'),(1288,471,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1289,472,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등\r\n','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 18:49:46','2026-02-13 14:55:56'),(1290,472,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 18:49:46','2026-01-14 14:19:36'),(1291,473,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1292,473,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1293,473,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/0ca235f0-1603-4e82-bf7d-a73f46b5ee3c.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 18:49:46','2026-01-13 16:38:35'),(1294,473,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/53001c75-06d3-4d10-937e-9735f2200a04.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:49:46','2026-01-13 16:38:44'),(1295,473,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1296,474,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1297,474,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 18:49:46','2026-01-14 14:53:43'),(1298,475,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1299,476,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1300,477,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 18:49:46','2026-01-14 14:20:44'),(1301,477,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1304,478,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 18:49:46','2026-01-09 18:49:46'),(1305,479,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1306,480,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1307,480,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:52:35','2026-01-14 11:41:44'),(1308,480,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1309,480,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1310,480,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1311,480,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1312,480,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 18:52:35','2026-01-14 14:24:46'),(1313,480,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1314,480,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1315,480,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:52:35','2026-01-14 11:41:50'),(1316,481,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:52:35','2026-01-13 17:04:06'),(1317,481,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:52:35','2026-01-13 17:04:09'),(1318,481,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 18:52:35','2026-01-14 15:34:36'),(1319,481,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1320,482,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 18:52:35','2026-02-13 14:56:13'),(1321,482,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 18:52:35','2026-01-14 14:27:40'),(1322,483,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1323,483,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1324,483,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/55e6c4c3-f706-49ce-b71c-0f7f4466963b.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 18:52:35','2026-01-13 16:39:16'),(1325,483,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/e693664f-e4eb-458e-b94c-105c8ce6fd91.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:52:35','2026-01-13 16:39:26'),(1326,483,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1327,484,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1328,484,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 18:52:35','2026-01-14 14:53:34'),(1329,485,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1330,486,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1331,487,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 18:52:35','2026-01-14 14:28:26'),(1332,487,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1335,488,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 18:52:35','2026-01-09 18:52:35'),(1336,489,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1337,490,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1338,490,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:53:56','2026-01-14 11:41:59'),(1339,490,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1340,490,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1341,490,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1342,490,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1343,490,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 18:53:56','2026-01-14 14:29:34'),(1344,490,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1345,490,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1346,490,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:53:56','2026-01-14 11:42:04'),(1347,491,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:53:56','2026-01-13 17:04:15'),(1348,491,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:53:56','2026-01-13 17:04:18'),(1349,491,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 18:53:56','2026-01-14 15:34:53'),(1350,491,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1351,492,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 18:53:56','2026-02-13 14:56:33'),(1352,492,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 18:53:56','2026-01-14 14:30:27'),(1353,493,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1354,493,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1355,493,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/fa2589f1-edf4-44ec-bf87-ed7f1a52a1d6.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 18:53:56','2026-01-13 16:40:05'),(1356,493,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/04d29e14-e96a-4e93-97eb-a97957dcd40a.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:53:56','2026-01-13 16:40:14'),(1357,493,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1358,494,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1359,494,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 18:53:56','2026-01-14 14:53:23'),(1360,495,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1361,496,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1362,497,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 18:53:56','2026-01-14 14:31:29'),(1363,497,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1366,498,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 18:53:56','2026-01-09 18:53:56'),(1367,499,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 18:56:02','2026-01-09 18:56:02'),(1368,500,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 18:56:02','2026-01-09 18:56:02'),(1369,500,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:56:02','2026-01-14 11:42:14'),(1370,500,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:56:02','2026-01-09 18:56:02'),(1371,500,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1372,500,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1373,500,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1374,500,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 18:56:03','2026-01-14 14:32:30'),(1375,500,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1376,500,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1377,500,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:56:03','2026-01-14 11:42:21'),(1378,501,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:56:03','2026-01-13 17:04:25'),(1379,501,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:56:03','2026-01-13 17:04:28'),(1380,501,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\",\"isPrice\":false},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 18:56:03','2026-01-14 15:35:12'),(1381,501,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1382,502,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 18:56:03','2026-02-13 14:56:45'),(1383,502,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 18:56:03','2026-01-14 14:33:18'),(1384,503,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1385,503,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1386,503,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/067f84a9-11d9-4662-8ac4-0aedf10a20ee.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 18:56:03','2026-01-13 16:40:44'),(1387,503,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/dcc23ec7-bcc1-4944-9a86-82ed1dce6657.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:56:03','2026-01-13 16:40:53'),(1388,503,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1389,504,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1390,504,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 18:56:03','2026-01-14 14:53:13'),(1391,505,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1392,506,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1393,507,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 18:56:03','2026-01-14 14:34:13'),(1394,507,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1397,508,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 18:56:03','2026-01-09 18:56:03'),(1398,509,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1399,510,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1400,510,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:57:57','2026-01-14 11:42:29'),(1401,510,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1402,510,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1403,510,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1404,510,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1405,510,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 18:57:57','2026-01-14 14:34:35'),(1406,510,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1407,510,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1408,510,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 18:57:57','2026-01-14 11:42:36'),(1409,511,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:57:57','2026-01-13 17:04:36'),(1410,511,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 18:57:57','2026-01-13 17:04:39'),(1411,511,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 18:57:57','2026-01-14 15:35:29'),(1412,511,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1413,512,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 18:57:57','2026-02-13 14:57:06'),(1414,512,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 18:57:57','2026-01-14 14:35:10'),(1415,513,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1416,513,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1417,513,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/445db492-fe3d-49cb-93c9-75f45a3796be.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 18:57:57','2026-01-13 16:41:18'),(1418,513,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/3107a1ea-eda0-46e0-bf1b-31a3101d2048.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 18:57:57','2026-01-13 16:41:26'),(1419,513,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1420,514,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 18:57:57','2026-01-09 18:57:57'),(1421,514,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 18:57:57','2026-01-14 14:53:04'),(1422,515,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 18:57:58','2026-01-09 18:57:58'),(1423,516,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 18:57:58','2026-01-09 18:57:58'),(1424,517,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 18:57:58','2026-01-14 14:41:29'),(1425,517,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 18:57:58','2026-01-09 18:57:58'),(1428,518,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 18:57:58','2026-01-09 18:57:58'),(1429,519,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1430,520,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1431,520,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:14:01','2026-01-14 11:42:45'),(1432,520,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1433,520,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1434,520,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1435,520,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1436,520,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 19:14:01','2026-01-14 14:42:04'),(1437,520,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1438,520,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1439,520,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:14:01','2026-01-14 11:42:51'),(1440,521,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:14:01','2026-01-13 17:05:09'),(1441,521,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:14:01','2026-01-13 17:05:12'),(1442,521,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 19:14:01','2026-01-14 15:35:45'),(1443,521,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1444,522,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 19:14:01','2026-02-13 14:57:36'),(1445,522,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 19:14:01','2026-01-14 14:42:50'),(1446,523,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1447,523,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1448,523,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/f4416424-4938-487e-a166-997dad33c06d.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 19:14:01','2026-01-13 16:41:59'),(1449,523,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/9642047d-c109-414c-ad3c-e92bf21ca2b1.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:14:01','2026-01-13 16:42:07'),(1450,523,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1451,524,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1452,524,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 19:14:01','2026-01-14 14:52:54'),(1453,525,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1454,526,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1455,527,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 19:14:01','2026-01-14 14:43:29'),(1456,527,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1459,528,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 19:14:01','2026-01-09 19:14:01'),(1460,529,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1461,530,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1462,530,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:15:40','2026-01-14 11:43:00'),(1463,530,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1464,530,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1465,530,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1466,530,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1467,530,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 19:15:40','2026-01-14 14:43:46'),(1468,530,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1469,530,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1470,530,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:15:40','2026-01-14 11:43:07'),(1471,531,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:15:40','2026-01-13 17:05:18'),(1472,531,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:15:40','2026-01-13 17:05:22'),(1473,531,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 19:15:40','2026-01-14 15:36:04'),(1474,531,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1475,532,2,'숙소 주변의 분위기를 설명해 주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 19:15:40','2026-02-13 14:58:07'),(1476,532,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 19:15:40','2026-01-14 14:44:15'),(1477,533,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1478,533,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1479,533,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/b3963a2a-c2f6-41d8-b401-867f1015a8e0.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 19:15:40','2026-01-13 16:42:35'),(1480,533,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/4c9f17c5-580b-4cc2-95ce-407b085e0fb7.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:15:40','2026-01-13 16:42:43'),(1481,533,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1482,534,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1483,534,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 19:15:40','2026-01-14 14:52:44'),(1484,535,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1485,536,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1486,537,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 19:15:40','2026-01-14 14:45:15'),(1487,537,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1490,538,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 19:15:40','2026-01-09 19:15:40'),(1491,539,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1492,540,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1493,540,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:18:23','2026-01-14 11:43:22'),(1494,540,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1495,540,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1496,540,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1497,540,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1498,540,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 19:18:23','2026-01-14 14:45:38'),(1499,540,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1500,540,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1501,540,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:18:23','2026-01-14 11:43:30'),(1502,541,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:18:23','2026-01-13 17:05:29'),(1503,541,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:18:23','2026-01-13 17:05:32'),(1504,541,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 19:18:23','2026-01-14 15:36:23'),(1505,541,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1506,542,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 19:18:23','2026-02-13 14:58:33'),(1507,542,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 19:18:23','2026-01-14 14:46:10'),(1508,543,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1509,543,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1510,543,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/3c56ade7-4705-4238-b357-a448d8182211.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 19:18:23','2026-01-13 16:43:11'),(1511,543,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/0119fc88-39f3-467c-8aa7-f6e5b0ce7693.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:18:23','2026-01-13 16:43:19'),(1512,543,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1513,544,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1514,544,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 19:18:23','2026-01-14 14:52:35'),(1515,545,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1516,546,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1517,547,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 19:18:23','2026-01-14 14:46:54'),(1518,547,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1521,548,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 19:18:23','2026-01-09 19:18:23'),(1522,549,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1523,550,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1524,550,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:21:00','2026-01-14 11:43:46'),(1525,550,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1526,550,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1527,550,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1528,550,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1529,550,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 19:21:00','2026-01-14 14:47:59'),(1530,550,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1531,550,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1532,550,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:21:00','2026-01-14 11:43:53'),(1533,551,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:21:00','2026-01-13 17:05:38'),(1534,551,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:21:00','2026-01-13 17:05:41'),(1535,551,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 19:21:00','2026-01-14 15:36:45'),(1536,551,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1537,552,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 19:21:00','2026-02-13 14:59:52'),(1538,552,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 19:21:00','2026-01-14 14:48:34'),(1539,553,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1540,553,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1541,553,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/bb4609cc-65a4-4ec2-8ef6-0284d4150582.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 19:21:00','2026-01-13 16:44:05'),(1542,553,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/73609c7c-bfb2-46cc-8598-db15c2b7dc07.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:21:00','2026-01-13 16:44:13'),(1543,553,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1544,554,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1545,554,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 19:21:00','2026-01-14 14:52:25'),(1546,555,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1547,556,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1548,557,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 19:21:00','2026-01-14 14:49:19'),(1549,557,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1552,558,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 19:21:00','2026-01-09 19:21:00'),(1553,559,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1554,560,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1555,560,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\"}',0,1,'2026-01-09 19:22:04','2026-01-14 11:44:16'),(1556,560,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1557,560,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1558,560,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1559,560,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1560,560,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 19:22:04','2026-01-14 14:52:08'),(1561,560,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1562,560,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1563,560,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:22:04','2026-01-14 11:44:22'),(1564,561,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:22:04','2026-01-13 17:05:49'),(1565,561,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:22:04','2026-01-13 17:05:51'),(1566,561,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 19:22:04','2026-01-14 15:37:03'),(1567,561,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1568,562,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등\r\n','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 19:22:04','2026-02-13 15:00:05'),(1569,562,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 19:22:04','2026-01-14 14:51:16'),(1570,563,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1571,563,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1572,563,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/9152836a-c6fe-4bd7-99b8-5ca198114d5f.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 19:22:04','2026-01-13 16:45:16'),(1573,563,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/d26beb98-eae6-4b19-abe4-36d7af09e502.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:22:04','2026-01-13 16:45:24'),(1574,563,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1575,564,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1576,564,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 19:22:04','2026-01-14 14:51:24'),(1577,565,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1578,566,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1579,567,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 19:22:04','2026-01-14 14:50:38'),(1580,567,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1583,568,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 19:22:04','2026-01-09 19:22:04'),(1584,569,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1585,570,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1586,570,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:24:20','2026-01-14 11:44:46'),(1587,570,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1588,570,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1589,570,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1590,570,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1591,570,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 19:24:20','2026-01-14 14:55:41'),(1592,570,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1593,570,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1594,570,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:24:20','2026-01-14 11:44:30'),(1595,571,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:24:20','2026-01-13 17:05:57'),(1596,571,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:24:20','2026-01-13 17:05:59'),(1597,571,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"isPrice\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 19:24:20','2026-01-14 15:37:21'),(1598,571,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1599,572,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등\r\n','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 19:24:20','2026-02-13 15:00:22'),(1600,572,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 19:24:20','2026-01-14 14:55:03'),(1601,573,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1602,573,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1603,573,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/f3f31eec-68aa-4341-a3e4-7f08806ec22f.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 19:24:20','2026-01-13 16:46:28'),(1604,573,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/a260f71b-a8e9-4310-9f4b-a94bca06291c.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:24:20','2026-01-13 16:46:36'),(1605,573,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1606,574,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1607,574,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 19:24:20','2026-01-14 14:54:56'),(1608,575,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1609,576,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1610,577,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 19:24:20','2026-01-14 14:54:39'),(1611,577,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1614,578,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 19:24:20','2026-01-09 19:24:20'),(1615,579,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 19:27:14','2026-01-09 19:27:14'),(1616,580,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 19:27:14','2026-01-09 19:27:14'),(1617,580,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:27:14','2026-01-14 11:44:55'),(1618,580,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:27:14','2026-01-09 19:27:14'),(1619,580,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:27:14','2026-01-09 19:27:14'),(1620,580,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 19:27:14','2026-01-09 19:27:14'),(1621,580,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 19:27:14','2026-01-09 19:27:14'),(1622,580,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 19:27:14','2026-01-14 14:55:51'),(1623,580,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 19:27:14','2026-01-09 19:27:14'),(1624,580,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 19:27:14','2026-01-09 19:27:14'),(1625,580,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:27:14','2026-01-14 11:45:01'),(1626,581,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:27:15','2026-01-13 17:06:05'),(1627,581,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:27:15','2026-01-13 17:06:08'),(1628,581,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 19:27:15','2026-01-14 15:37:37'),(1629,581,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 19:27:15','2026-01-09 19:27:15'),(1630,582,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등\r\n','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 19:27:15','2026-02-13 15:00:38'),(1631,582,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 19:27:15','2026-01-14 14:56:44'),(1632,583,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:27:15','2026-01-09 19:27:15'),(1633,583,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:27:15','2026-01-09 19:27:15'),(1634,583,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/2093025b-b504-45a5-8161-9dcf0ae96f0a.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 19:27:15','2026-01-13 16:47:26'),(1635,583,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/4f862656-db9d-43b1-a069-65d606e82267.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:27:15','2026-01-13 16:47:52'),(1636,583,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 19:27:15','2026-01-09 19:27:15'),(1637,584,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 19:27:15','2026-01-09 19:27:15'),(1638,584,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 19:27:15','2026-01-14 14:56:57'),(1639,585,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 19:27:15','2026-01-09 19:27:15'),(1640,586,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 19:27:15','2026-01-09 19:27:15'),(1641,587,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 19:27:15','2026-01-14 14:57:34'),(1642,587,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 19:27:15','2026-01-09 19:27:15'),(1645,588,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 19:27:15','2026-01-09 19:27:15'),(1646,589,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1647,590,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1648,590,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:29:23','2026-01-14 11:45:09'),(1649,590,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1650,590,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1651,590,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1652,590,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1653,590,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 19:29:23','2026-01-14 14:57:51'),(1654,590,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1655,590,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1656,590,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:29:23','2026-01-14 11:45:15'),(1657,591,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:29:23','2026-01-13 17:06:14'),(1658,591,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:29:23','2026-01-13 17:06:18'),(1659,591,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 19:29:23','2026-01-14 15:37:53'),(1660,591,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1661,592,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 19:29:23','2026-02-13 15:01:05'),(1662,592,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 19:29:23','2026-01-14 14:58:26'),(1663,593,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1664,593,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1665,593,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/c5d573c1-d0ec-42db-a102-b065156ca76b.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 19:29:23','2026-01-13 16:49:18'),(1666,593,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/c00e79b7-7f6a-4b62-ab07-19a2e7c7bd06.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:29:23','2026-01-13 16:49:26'),(1667,593,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1668,594,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1669,594,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 19:29:23','2026-01-14 14:58:39'),(1670,595,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1671,596,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1672,597,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 19:29:23','2026-01-14 14:59:18'),(1673,597,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1676,598,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 19:29:23','2026-01-09 19:29:23'),(1677,599,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1678,600,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1679,600,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:30:29','2026-01-14 11:45:23'),(1680,600,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1681,600,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1682,600,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1683,600,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1684,600,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 19:30:29','2026-01-14 14:59:37'),(1685,600,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1686,600,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1687,600,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:30:29','2026-01-14 11:45:28'),(1688,601,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:30:29','2026-01-13 17:06:25'),(1689,601,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:30:29','2026-01-13 17:06:28'),(1690,601,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 19:30:29','2026-01-14 15:38:13'),(1691,601,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1692,602,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등\r\n','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 19:30:29','2026-02-13 15:01:24'),(1693,602,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 19:30:29','2026-01-14 15:00:08'),(1694,603,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1695,603,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1696,603,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/a5635081-3f34-4c57-9b44-90fda1af401e.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 19:30:29','2026-01-13 16:50:09'),(1697,603,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/604c8c3e-2cf8-4ed8-b449-8cd0751b750f.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:30:29','2026-01-13 16:50:29'),(1698,603,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1699,604,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1700,604,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 19:30:29','2026-01-14 15:00:18'),(1701,605,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1702,606,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1703,607,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 19:30:29','2026-01-14 15:00:59'),(1704,607,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1707,608,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 19:30:29','2026-01-09 19:30:29'),(1708,609,1,'안내사항','본 페이지에서 작성하시는 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\r\n\r\n보다 정확한 설계와 원활한 진행을 위해, 각 항목을 충분히 검토하신 후 신중하게 작성해 주시기 바랍니다.\r\n\r\n아래 안내사항에 동의하셔야 다음 단계로 이동할 수 있습니다.','AGREEMENT',NULL,10,500,'{\"agreementItems\":[\"본 단계에서 작성하신 모든 내용은 홈페이지 제작에 직접 반영되는 기초 자료로 활용됩니다.\\n\\n작성 내용의 정확도에 따라 제작 방향 및 결과물이 달라질 수 있습니다.\",\"작성 중인 정보는 중간 저장이 가능하며, PC와 모바일 환경 모두에서 동일하게 적용됩니다. \\n작성 도중 화면을 벗어나더라도 저장된 정보는 유지됩니다.\",\"선택하신 홈페이지 타입은 전체 제작 방향의 기준이 됩니다. 타입 선택 이후에는 구조 변경이 제한될 수 있으므로, 각 타입의 특성과 활용 목적을 충분히 확인하신 후 선택해 주세요.\",\"제출 이후에는 전체 구조 변경이 제한될 수 있으며, 필요한 경우 별도 협의를 통해 조정됩니다.\",\"제출된 정보는 순차적으로 검토되며, 진행 상황에 따라 안내까지 일정 시간이 소요될 수 있습니다.\",\"입력하신 정보는 홈페이지 제작 및 관련 협의를 위한 목적으로만 사용됩니다.\\n마케팅, 광고, 제3자 제공 등 다른 용도로는 활용되지 않습니다.\",\"수집된 정보는 입력일로부터 최대 1년간 보관되며, 이후 안전하게 파기됩니다.\"]}',0,1,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1709,610,2,'사업자 등록정보','사업자 등록증 파일 또는 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"maxFiles\":1,\"maxSizeMB\":10}',0,0,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1710,610,4,'홈페이지 담당자 연락처','홈페이지 제작 및 관련 안내를 담당하시는 분의 연락처를 입력해 주세요.','TEXT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"\",\"\"],\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:31:28','2026-01-14 11:45:44'),(1711,610,3,'통장 사본','정산 및 행정 확인을 위해 통장 사본 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1712,610,6,'농어촌민박신고번호','농어촌민박 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1713,610,7,'통신판매번호','통신판매업 신고증 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"선택지 1\",\"hasInput\":false}]}',0,0,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1714,610,8,'숙소 주소',' ','ADDR',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"지번 주소\",\"hasInput\":true,\"placeholder\":\"지번 주소를 입력해 주세요.\"},{\"label\":\"도로명 주소\",\"hasInput\":true,\"placeholder\":\"도로명 주소를 입력해 주세요.\"}]}',0,1,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1715,610,9,'이메일 주소',' 안내 메일 수신을 위한 이메일 주소를 입력해 주세요.','TEXT',NULL,10,500,'{\"placeholder\":\"이메일 주소를 입력해 주세요.\"}',0,1,'2026-01-09 19:31:28','2026-01-14 15:03:59'),(1716,610,10,'SNS 계정','현재 운영 중인 SNS가 있다면 선택 후 정보를 입력해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"인스타그램\",\"hasInput\":true,\"placeholder\":\"인스타그램 주소를 입력해 주세요.\"},{\"label\":\"네이버 블로그\",\"hasInput\":true,\"placeholder\":\"네이버 블로그 주소를 입력해 주세요.\"},{\"label\":\"기타\",\"hasInput\":true,\"placeholder\":\"사용중이신 SNS 주소를 입력해 주세요.\"}]}',0,0,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1717,610,1,'숙소명','사업자 등록증에 기재된 공식 명칭을 기준으로 작성해 주세요.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"숙소명(한글)\",\"placeholder2\":\"숙소명(영문)\"}',0,1,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1718,610,5,'숙소 연락처','숙소 예약 문의를 받으실 연락처를 입력해 주세요. \r\n해당 번호는 홈페이지에 노출됩니다.','TEXT',NULL,10,500,'{\"placeholder\":\"예시 : 01000000000\",\"isNumber\":true}',0,1,'2026-01-09 19:31:28','2026-01-14 11:45:37'),(1719,611,1,'네이버 계정','네이버 스마트플레이스 등록 및 검색 최적화에 사용될 계정입니다. 현재 사용 중이거나, 향후 운영에 사용할 네이버 계정을 입력해 주세요. ※ 해당 정보는 네이버 연동 설정 목적에 한해 활용됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"아이디를 입력해 주세요.\",\"placeholder2\":\"비밀번호를 입력해 주세요.\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:31:28','2026-01-13 17:06:35'),(1720,611,2,'게시판 관리자 계정(신규 생성)','공지사항, 팝업, 수정 요청 등 홈페이지 관리에 사용될 관리자 계정입니다. 실제 사용하실 아이디와 비밀번호를 입력해 주세요. ※ 해당 계정은 홈페이지 관리자 권한으로 설정됩니다.','MULTI_TEXT',NULL,10,500,'{\"placeholder1\":\"관리자 아이디\",\"placeholder2\":\"관리자 비밀번호\",\"isIdPassword\":true,\"isNumber\":false}',0,1,'2026-01-09 19:31:28','2026-01-13 17:06:38'),(1721,611,3,'도메인','홈페이지 주소를 어떻게 사용할 예정인지 선택해 주세요. 예) www.stay-season.com','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"이미 사용 중인 홈페이지 주소가 있습니다.\",\"hasInput\":true,\"placeholder\":\"사용 중인 도메인 주소를 입력해 주세요.\"},{\"label\":\"새 홈페이지 주소가 필요합니다.\",\"hasInput\":true,\"placeholder\":\"원하는 도메인 주소를 작성해 주세요. (예: www.stay-season.com)\"},{\"label\":\"잘 모르겠습니다. / 추천받고 싶습니다.\",\"hasInput\":false,\"placeholder\":\"원하시는 도메인이 있다면 입력해 주세요. (예: www.stay-season.com)\"}]}',0,1,'2026-01-09 19:31:28','2026-01-14 15:38:28'),(1722,611,4,'실시간 예약 프로그램','홈페이지에서 고객이 바로 예약할 수 있는 시스템을 사용하고 계신가요? 현재 사용 중이거나, 연동을 희망하는 예약 서비스를 선택해 주세요. (복수 선택 가능)','CHECKBOX',NULL,10,500,'{\"multiple\":true,\"checkboxes\":[{\"label\":\"떠나요\",\"hasInput\":true,\"placeholder\":\"떠나요 예약링크 주소를 입력해 주세요.\"},{\"label\":\"야놀자\",\"hasInput\":true,\"placeholder\":\"야놀자 예약링크 주소를 입력해 주세요.\"},{\"label\":\"온다\",\"hasInput\":true,\"placeholder\":\"온다 예약링크 주소를 입력해 주세요.\"},{\"label\":\"네이버\",\"hasInput\":true,\"placeholder\":\"네이버 스마트플레이스 링크를 입력해 주세요.\"},{\"label\":\"여기어때\",\"hasInput\":true,\"placeholder\":\"여기어때 예약링크 주소를 입력해 주세요.\"},{\"label\":\"추천받고 싶습니다.\",\"hasInput\":false}]}',0,1,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1723,612,2,'숙소(업체) 소개 글을 간단하게 작성해주세요.','건축 스토리 / 운영컨셉 / 소비자에게 전달하고 싶은 내용 / 주변풍경 등\r\n','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 창밖으로 펼쳐지는 산과 숲, 하루 종일 조용한 휴식이 가능한 공간 / 바다와 맞닿은 해안 마을, 산책만으로도 여행이 되는 곳\"}',1,1,'2026-01-09 19:31:28','2026-02-13 15:01:38'),(1724,612,1,'홈페이지에 처음 접속했을 때 가장 먼저 보여질 대표 문구를 작성해 주세요.','숙소의 분위기나 가장 강조하고 싶은 특징을 한 문장으로 표현해 주시면 됩니다.','TEXTAREA',NULL,3,500,'{\"placeholder\":\"예시) 바다를 가장 가까이에서 누리는 프라이빗 풀빌라 / 일상에서 벗어나 조용히 머물 수 있는 숲속의 쉼터\"}',1,1,'2026-01-09 19:31:28','2026-01-14 15:02:10'),(1725,613,1,'로고 제작 여부','신규 로고 제작 여부를 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"로고 제작이 필요합니다.\",\"hasInput\":true,\"placeholder\":\"로고 디자인 요청사항을 작성해주세요\"},{\"label\":\"기존 로고가 존재합니다. (하단 질문에서 이미지 첨부해 주세요)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1726,613,2,'로고 이미지 첨부','기존에 사용 중인 로고가 있다면 이미지를 첨부해 주세요. ','FILE',NULL,10,500,'',0,0,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1727,613,4,'홈페이지에서 전달하고 싶은 전체적인 사진 분위기를 선택해 주세요.','홈페이지 전반의 사진 보정 스타일을 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/40751f11-95ab-4f97-8b7d-85ebc58ee763.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"밝고 생동감 있는 분위기\",\"hasInput\":false},{\"label\":\"차분하고 정돈된 분위기\",\"hasInput\":false}]}',0,1,'2026-01-09 19:31:28','2026-01-13 16:51:22'),(1728,613,5,'숙소의 이미지를 가장 잘 표현할 수 있는 사진 색감 방향을 선택해 주세요.','사진의 전체 색감 톤을 기준으로 선택해 주세요.','CHECKBOX','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/options/66bc6c01-2132-45d4-afb7-c7830b74a9a6.jpg',10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"아늑하고 편안한 느낌(휴식, 감성숙소에 어울리는 톤)\",\"hasInput\":false},{\"label\":\"깔끔하고 세련된 느낌(바다, 모던하고 차분한 공간에 어울리는 톤)\",\"hasInput\":false}]}',0,1,'2026-01-09 19:31:28','2026-01-13 16:51:32'),(1729,613,3,'로고 제작 옵션을 선택해주세요.','로고 제작이 필요한 경우, 제작 방식을 선택해 주세요.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"무료 로고 : 텍스트 형태의 간단한 로고 디자인\",\"hasInput\":false},{\"label\":\"유료 로고 : 숙소 브랜드에 맞춘 맞춤형 로고 디자인 제작\",\"hasInput\":false}]}',0,0,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1730,614,1,'객실',' ','PARLOR',NULL,10,500,'',0,1,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1731,614,2,'추가 인원 요금','기준 인원을 초과할 경우 발생하는 추가 요금을 입력해 주세요.  추가 인원 요금은 예약 시 자동 계산 또는 안내 기준으로 활용됩니다.','CHECKBOX',NULL,10,500,'{\"placeholder\":\"예시) 유아:\",\"placeholder1\":\"유아/아동 추가 요금\",\"placeholder2\":\"성인 추가 요금\",\"isNumber\":true,\"checkboxes\":[{\"label\":\"유아/아동\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true},{\"label\":\"성인\",\"hasInput\":true,\"placeholder\":\"금액을 작성해주세요.\",\"isPrice\":true}],\"multiple\":true}',0,0,'2026-01-09 19:31:28','2026-01-14 15:02:01'),(1732,615,1,'스페셜',' ','SPECIAL',NULL,10,500,'',0,1,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1733,616,1,'여행안내','숙소 주변에서 가볍게 둘러볼 수 있는 여행지를 소개하는 영역입니다. 장소의 이름만 입력해 주시면 되며, 입력해 주신 여행지는 숙소 기준 거리순으로 정리됩니다. 설명 문구와 디자인 구성은 제작 과정에서 반영됩니다.','CHECKBOX',NULL,10,500,'{\"multiple\":false,\"checkboxes\":[{\"label\":\"추천받고 싶습니다. (주변 지역에 맞는 여행지를 제안해 드립니다.)\",\"hasInput\":false},{\"label\":\"직접 입력하겠습니다.\",\"hasInput\":true,\"placeholder\":\"예시 : OO해수욕장, ㅁㅁ전망대, ㅁㅁ카페거리\"}]}',0,1,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1734,617,1,'예약 관련 안내','해당하는 숙소 이용 규칙에 체크해 주세요. 수정이 필요한 문구는 체크 후 자유롭게 수정해 주시면 됩니다.','CHECKBOX_INPUT',NULL,10,500,'{\"multiple\":true,\"inputs\":[\"예약자명과 입금자명이 다를 경우, 반드시 사전 확인 전화를 부탁드립니다.\",\"실시간 예약 달력을 통해 예약하신 경우, 발송되는 안내 문자(객실 정보, 투숙일, 요금)를 확인해 주세요.\",\"기준 인원을 초과할 경우 입실 및 환불이 불가합니다.\",\"2실 이상 예약을 원하실 경우, 사전 협의 후 예약해 주시기 바랍니다.\",\"입실 시간은 이용 당일 15:00 ~ 22:00입니다.\",\"22:00 이후 도착 예정인 경우, 반드시 사전에 연락해 주시기 바랍니다. 사전 연락이 없을 경우 입실이 제한될 수 있습니다.\",\"퇴실 시간은 마지막 이용일 11:00까지입니다.\",\"다음 이용 고객을 위해 퇴실 시간을 반드시 지켜주시기 바랍니다.\",\"퇴실 시 객실 정리 후 점검을 받아주시기 바랍니다.\",\"이용 중 비품 또는 시설물 파손 시, 즉시 숙소 관리자에게 알려주시기 바랍니다.\",\"쓰레기는 지정된 장소에 분리 배출해 주시기 바랍니다.\",\"오후 11시 이후에는 바비큐장 이용 및 고성방가를 삼가 주시기 바랍니다. (타 객실 이용객을 위한 안내입니다.)\",\"객실 내에서는 육류(삼겹살, 튀김류 등) 조리를 금지하고 있습니다. 화재 및 냄새로 인한 불편을 방지하기 위해, 실외 지정된 장소 또는 바비큐장을 이용해 주세요.\",\"미성년자는 보호자 동반 시에만 이용 가능합니다.\",\"반려동물 동반 입실은 불가합니다.\",\"객실 내에서는 절대 금연입니다.\"]}',0,1,'2026-01-09 19:31:28','2026-01-14 15:01:51'),(1735,617,4,'예약 및 이용안내(추가사항)','위 안내사항 외에, 숙소 이용 시 추가로 안내하고 싶은 내용이 있다면 자유롭게 작성해 주세요. 해당 내용은 예약 및 이용안내 항목에 함께 노출됩니다.','TEXTAREA',NULL,10,500,'',0,0,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1738,618,1,'환불',' ','REFUND',NULL,10,500,'',0,1,'2026-01-09 19:31:28','2026-01-09 19:31:28'),(1740,450,0,'대표자명',' ','TEXT',NULL,10,500,'{\"placeholder\":\"대표자명을 작성해주세요.\"}',0,1,'2026-01-13 09:49:33','2026-01-13 09:49:55'),(1742,470,0,'대표자명',' ','TEXT',NULL,10,500,'{\"placeholder\":\"대표자명을 작성해주세요.\"}',0,1,'2026-01-13 09:50:19','2026-01-13 09:50:19'),(1743,480,0,'대표자명',' ','TEXT',NULL,10,500,'{\"placeholder\":\"대표자명을 작성해주세요.\"}',0,1,'2026-01-13 09:50:27','2026-01-13 09:50:27'),(1744,490,0,'대표자명',' ','TEXT',NULL,10,500,'{\"placeholder\":\"대표자명을 작성해주세요.\"}',0,1,'2026-01-13 09:50:36','2026-01-13 09:50:36'),(1745,500,0,'대표자명',' ','TEXT',NULL,10,500,'{\"placeholder\":\"대표자명을 작성해주세요.\"}',0,1,'2026-01-13 09:50:45','2026-01-13 09:50:45'),(1746,510,0,'대표자명',' ','TEXT',NULL,10,500,'{\"placeholder\":\"대표자명을 작성해주세요.\"}'