DROP TABLE IF EXISTS `PORTFOLIO`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `PORTFOLIO` (
  `PORTFOLIO_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '포트폴리오 ID',
  `CATEGORY_ID` bigint DEFAULT NULL COMMENT '카테고리 ID',
  `PORTFOLIO_TITLE` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '포트폴리오 제목',
  `PORTFOLIO_DESCRIPTION` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '포트폴리오 설명',
  `PORTFOLIO_DOMAIN` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '포트폴리오 도메인',
  `PORTFOLIO_ORDERS` int DEFAULT NULL COMMENT '포트폴리오 순서',
  `PORTFOLIO_SLUG` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '포트폴리오 슬러그',
  `PORTFOLIO_THUMBNAIL` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '포트폴리오 썸네일',
  `PORTFOLIO_IS_ACTIVE` tinyint(1) DEFAULT NULL COMMENT '포트폴리오 여부 활성',
  `REGIST_DATE` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '생성 일시',
  `MODIFY_DATE` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '수정 일시',
  PRIMARY KEY (`PORTFOLIO_ID`),
  KEY `FK_PORTFOLIO_CATEGORY_ID_CATEGORY_CATEGORY_ID` (`CATEGORY_ID`),
  CONSTRAINT `FK_PORTFOLIO_CATEGORY_ID_CATEGORY_CATEGORY_ID` FOREIGN KEY (`CATEGORY_ID`) REFERENCES `CATEGORY` (`CATEGORY_ID`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=86 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='포트폴리오';
/*!40101 SET character_set_client = @saved_cs_client */;

