INSERT INTO `PORTFOLIO` VALUES (62,18,'표준형1','베이지톤 배경과 영문 필기체 조합으로 감성적인 분위기를 강조한 타입입니다.\r\n\r\n#오션뷰 #풀빌라','https://www.always-design.co.kr/type02-1/',2,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/d4d7d133-592e-481b-8af6-146e507af0eb.png',1,'2026-01-09 18:27:31','2026-01-19 15:42:35'),(64,18,'표준형2','투톤 베이지 컬러와 라운드형 프레임을 활용한 타입입니다.\r\n\r\n#풀빌라','https://www.always-design.co.kr/type03/',4,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/4b59726c-1d3b-4892-8445-5fc640ee846d.png',1,'2026-01-09 18:49:46','2026-01-19 12:49:31'),(65,10,'무드형1','그레이 톤 배경과 명조체 조합으로 감성적인 독채 숙소에 잘 어울리는 타입입니다.\r\n\r\n#독채 #한옥','https://www.always-design.co.kr/type04-1/',5,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/e85d20dc-b3ff-44a5-9292-99e8a5fc99ae.png',1,'2026-01-09 18:52:35','2026-01-20 14:31:28'),(66,9,'테마형1','수직 배열된 타이포그래피와 사진 배치를 통해 동양적인 미감을 강조한 타입입니다.\r\n\r\n#독채 #한옥','https://www.always-design.co.kr/type04-2/',6,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/ecbad92a-08b0-4646-9224-a1813071c051.png',1,'2026-01-09 18:53:56','2026-01-19 15:43:42'),(67,9,'테마형2','블루 포인트 컬러를 사용해 오션뷰나 풀빌라 숙소의 분위기를 효과적으로 살릴 수 있는 타입입니다.\r\n\r\n#오션뷰','https://www.always-design.co.kr/type05-1/',7,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/f3d994f9-8e7c-417e-9a63-3a02988c1b95.png',1,'2026-01-09 18:56:02','2026-01-19 15:43:18'),(68,10,'무드형2','맑은 블루 톤을 중심으로, \r\n깔끔하고 시원한 인상이 드러나도록 구성된 타입입니다.','https://www.always-design.co.kr/type05-2/',8,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/45e79346-30bc-412e-9bf5-fd91a696d5b0.png',0,'2026-01-09 18:57:57','2026-01-16 15:30:05'),(69,18,'표준형3','감성적인 서체와 깨끗한 화이트 톤이 조화를 이루어 다양한 숙소에 무난하게 적용할 수 있는 타입입니다.\r\n\r\n#모던','https://www.always-design.co.kr/type06-1/',9,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/b0082557-c7a5-4f77-addf-a5cc1ec6f861.png',1,'2026-01-09 19:14:01','2026-01-19 12:49:24'),(70,9,'테마형3','스토리 페이지로 숙소의 이야기를 풍부하게 전달하며 세로컷 사용으로 모바일에 최적화된 타입입니다.\r\n\r\n#독채 #풀빌라','https://www.always-design.co.kr/type06-2/',10,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/df44cdf7-b21a-403a-8f53-edad1a13b07d.png',1,'2026-01-09 19:15:40','2026-01-20 14:28:50'),(71,10,'무드형2','차분한 톤의 구성과 썸네일 중심 설계로 숙소의 다양한 매력을 자연스럽게 보여주는 타입입니다.\r\n\r\n#감성 #모던','https://www.always-design.co.kr/type07-1/',11,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/4a743d60-69b0-4cda-9aed-d4991a37a788.png',1,'2026-01-09 19:18:23','2026-01-19 15:48:01'),(72,10,'무드형3','객실 프리뷰 페이지를 별도로 구성해 호텔이나 리조트의 객실 정보를 한눈에 보기 좋게 정리한 타입입니다.\r\n\r\n#호텔','https://www.always-design.co.kr/type07-2/',12,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/9802f6d4-eb3c-4006-8b25-110992b4f130.png',1,'2026-01-09 19:21:00','2026-01-19 15:48:12'),(73,18,'표준형4','다채로운 썸네일 구성과 감성적인 분위기로 다양한 숙소에 적합한 타입입니다.\r\n\r\n#감성 #모던','https://www.always-design.co.kr/type08-1/',13,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/1b7abb31-5b35-44d2-b758-1711a2a04357.png',1,'2026-01-09 19:22:04','2026-01-19 15:42:53'),(74,18,'표준형5','소품, 공간, 구조 등 다양한 요소를 감성컷과 디테일컷으로 풍부하게 표현할 수 있는 타입입니다.\r\n\r\n#모던 #풀빌라','https://www.always-design.co.kr/type08-2/',14,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/1b2bd5d0-4753-414a-a031-cf6504a300db.png',1,'2026-01-09 19:24:20','2026-01-19 15:43:02'),(75,9,'테마형4','슬라이드 이미지에 시선을 집중할 수 있도록 구성된 이미지 중심의 디자인 타입입니다.\r\n\r\n#료칸 #풀빌라','https://www.always-design.co.kr/type08-3/',15,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/96c5325a-87c8-460b-979b-ae4cd29dbef9.png',1,'2026-01-09 19:27:14','2026-01-20 14:30:12'),(76,11,'컨셉형1','기존 홈페이지와는 색다른 레이아웃에 모션 효과를 더한 감각적인 타입입니다.\r\n\r\n#풀빌라 #오션뷰','https://www.always-design.co.kr/type09-1/',16,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/56f358db-8ff1-4784-b540-c4a6381c2cb1.png',1,'2026-01-09 19:29:23','2026-01-19 15:48:24'),(77,11,'컨셉형2','다양한 디자인 형태를 활용해 개성과 유니크함을 강조할 수 있는 타입입니다.\r\n\r\n#감성 #모던','https://www.always-design.co.kr/type09-2/',18,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/43c28b98-c47f-47c2-8321-70dc6a541c54.png',1,'2026-01-09 19:30:29','2026-01-23 08:59:50'),(78,11,'컨셉형3','다채로운 컬러와 라운드형 디자인으로 경쾌한 분위기를 연출하는 타입입니다.\r\n\r\n#독채 #감성','https://www.always-design.co.kr/type09-3/',18,'1','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/6379599e-9607-45ed-869a-20049e3510d0.png',1,'2026-01-09 19:31:28','2026-01-19 15:50:19'),(79,18,'테스트','테스트','테스트',99,'테스트',NULL,0,'2026-01-13 10:08:00','2026-01-16 15:31:17'),(80,12,'서라온','고객 맞춤으로 제작된 \r\n**주문형** 홈페이지 사례입니다.','https://www.always-design.co.kr/typeA/',19,'19','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/cae662a7-e2a8-4ef8-a185-99a661506670.jpg',1,'2026-01-14 15:06:05','2026-01-14 15:51:46'),(81,12,'오젠하이 웰니스','고객 맞춤으로 제작된 \r\n**주문형** 홈페이지 사례입니다.','https://www.always-design.co.kr/typeB/',20,'20','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/da9f9301-1473-434e-b332-db20ae10574e.jpg',1,'2026-01-14 15:49:57','2026-01-14 15:51:52'),(82,12,'품에, 고모리','고객 맞춤으로 제작된 \r\n**주문형** 홈페이지 사례입니다.','https://www.always-design.co.kr/typeC/',21,'21','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/b8f170e0-f975-4c76-a35c-db1fc821b468.jpg',1,'2026-01-14 15:52:52','2026-01-14 15:53:36'),(83,12,'담해','고객 맞춤으로 제작된 \r\n**주문형** 홈페이지 사례입니다.','https://www.always-design.co.kr/typeD/',22,'22','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/6b849467-5945-405c-ba14-ad1dbfc39e0a.jpg',1,'2026-01-14 15:53:45','2026-01-14 15:54:31'),(84,12,'오션블리스','고객 맞춤으로 제작된 \r\n**주문형** 홈페이지 사례입니다.','https://www.always-design.co.kr/typeE/',23,'23','https://portfolio-always-files.s3.ap-northeast-2.amazonaws.com/portfolio/7c2cf2