CREATE TABLE `REFRESH_TOKEN` (
  `REFRESH_TOKEN_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '리프레쉬 토큰 ID',
  `MEMBER_ID` bigint DEFAULT NULL COMMENT '회원 ID',
