  `MODIFY_DATE` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '수정 일시',
  PRIMARY KEY (`REFRESH_TOKEN_ID`),
  KEY `FK_REFRESH_TOKEN_MEMBER_ID_MEMBER_MEMBER_ID` (`MEMBER_ID`),
